// ─── Route by command (supports text, photos, and media groups) ────────────
const trigger = $('Webhook Trigger').first();
const body = trigger.json.body;
const msg = body.message || {};
const text = (msg.text || msg.caption || '').trim();
const chatId = msg.chat?.id;
const msgId = msg.message_id;
const mediaGroupId = msg.media_group_id || null;

let sessionId = 'none';
let responseText = '';

const OPENCODE_URL = 'http://opencode-proxy:3284';
const TG_TOKEN = '%TELEGRAM_TOKEN%';

// ─── Buffer album photos ─────────────────────────────────────────
if (mediaGroupId) {
  const photos = msg.photo || [];
  let fileId = null;
  if (photos.length > 0) fileId = photos[photos.length - 1].file_id;
  if (msg.document && msg.document.mime_type && msg.document.mime_type.startsWith('image/')) {
    fileId = msg.document.file_id;
  }
  if (fileId) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: `${OPENCODE_URL}/media-group/add`,
        body: { mediaGroupId, fileId },
        json: true
      });
    } catch (e) { /* ignore buffer errors */ }
  }
}

try {
  if (text === '/new') {
    const result = await this.helpers.httpRequest({
      method: 'POST',
      url: `${OPENCODE_URL}/session/clear`,
      body: { chatId },
      json: true
    });
    sessionId = 'none';
    responseText = result.message || '새로운 대화를 시작합니다. 무엇을 도와드릴까요?';
  } else {
    const result = await this.helpers.httpRequest({
      method: 'GET',
      url: `${OPENCODE_URL}/session?chatId=${chatId}`,
      json: true
    });
    sessionId = result.sessionId || 'none';
  }
} catch (e) { /* ignore */ }

const sessionDisplay = sessionId.replace(/^ses_/, '');

// ─── /stock ──────────────────────────────────────────────────────
if (text.toLowerCase().startsWith('/stock')) {
  const photos = msg.photo || [];
  const photoFileIds = [];
  if (photos.length > 0) {
    photoFileIds.push(photos[photos.length - 1].file_id);
  }
  if (msg.document && msg.document.mime_type && msg.document.mime_type.startsWith('image/')) {
    photoFileIds.push(msg.document.file_id);
  }
  return [{ json: { route: 'stock', chatId, msgId, message: text, sessionId: sessionDisplay, photoFileIds, mediaGroupId } }];
}

// ─── Album photo without /stock caption: silently ignore ─────────
if (mediaGroupId && (msg.photo || msg.document)) {
  return [{ json: { route: 'ignore', chatId, msgId, message: '', sessionId: sessionDisplay } }];
}

// ─── /naverblog ──────────────────────────────────────────────────
if (text.toLowerCase().startsWith('/naverblog')) {
  const topic = text.replace(/^\/naverblog\s*/i, '').trim();
  return [{ json: { route: 'naverblog', topic, chatId, msgId, message: text, sessionId: sessionDisplay } }];
}

// ─── Default: OpenCode ───────────────────────────────────────────
return [{ json: { route: 'opencode', topic: '', chatId, msgId, message: text, sessionId: sessionDisplay, responseText } }];

