// ─── Download Photos from Telegram ────────────────────────────────────────
const OPENCODE_URL = 'http://opencode-proxy:3284';
const routeData = $('Route by Command').first().json;
let photoFileIds = routeData.photoFileIds || [];
const mediaGroupId = routeData.mediaGroupId || null;
const chatId = routeData.chatId;
const msgId = routeData.msgId;
const sessionId = routeData.sessionId || 'none';
const TG_TOKEN = '%TELEGRAM_TOKEN%';

// If this is a media group (album), wait and collect ALL buffered photos
if (mediaGroupId) {
  try {
    const collected = await this.helpers.httpRequest({
      method: 'GET',
      url: `${OPENCODE_URL}/media-group/collect?id=${mediaGroupId}&waitMs=2000`,
      json: true,
      timeout: 10000
    });
    if (collected.fileIds && collected.fileIds.length > 0) {
      photoFileIds = collected.fileIds;
    }
  } catch (e) {
    console.error('Failed to collect media group:', e.message);
  }
}

if (photoFileIds.length === 0) {
  return [{ json: { chatId, msgId, sessionId, imageUrls: [], error: '사진이 첨부되지 않았습니다. /stock 명령어와 함께 주식 스크린샷을 보내주세요.' } }];
}

const imageUrls = [];
for (const fileId of photoFileIds) {
  try {
    const fileInfo = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.telegram.org/bot${TG_TOKEN}/getFile?file_id=${fileId}`,
      json: true
    });
    if (fileInfo.ok && fileInfo.result.file_path) {
      const downloadUrl = `https://api.telegram.org/file/bot${TG_TOKEN}/${fileInfo.result.file_path}`;
      imageUrls.push(downloadUrl);
    }
  } catch (e) {
    console.error(`Failed to get file info for ${fileId}:`, e.message);
  }
}

return [{ json: { chatId, msgId, sessionId, imageUrls } }];

// ─── Analyze Stock Images via Gemini Vision ──────────────────────────────
const OPENCODE_URL = 'http://opencode-proxy:3284';
const { chatId, msgId, sessionId, imageUrls } = $json;

if (!imageUrls || imageUrls.length === 0) {
  return [{ json: { chatId, msgId, sessionId, stockData: null, error: $json.error || '이미지를 다운로드할 수 없습니다.' } }];
}

const analysisPrompt = `You are a financial data extraction expert. Analyze the attached stock portfolio screenshot(s) carefully.

Extract ALL stock holdings visible in the image(s). For each stock, extract:
- name: The stock name (in Korean or English as shown)
- ticker: The ticker/symbol if visible
- shares: Number of shares held
- totalValue: Current total value in KRW (원)
- profitLoss: Profit or loss amount in KRW (원) — positive means gain, negative means loss
- profitLossPercent: Profit or loss percentage
- market: "domestic" (국내) or "overseas" (해외)

Also calculate:
- totalPortfolioValue: Sum of all stock values
- totalProfitLoss: Sum of all profit/loss
- overallProfitPercent: Overall portfolio profit percentage

Return ONLY valid JSON in this exact format (no other text):
{
  "stocks": [
    { "name": "...", "ticker": "...", "shares": 0, "totalValue": 0, "profitLoss": 0, "profitLossPercent": 0, "market": "domestic" }
  ],
  "totalPortfolioValue": 0,
  "totalProfitLoss": 0,
  "overallProfitPercent": 0
}`;

try {
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: `${OPENCODE_URL}/analyze-image`,
    body: { prompt: analysisPrompt, imageUrls, chatId: String(chatId) },
    json: true,
    timeout: 300000
  });

  let rawText = result.text || '';
  const jsonMatch = rawText.match(/\{[\s\S]*\"stocks\"[\s\S]*\}/);
  if (jsonMatch) {
    const stockData = JSON.parse(jsonMatch[0]);
    return [{ json: { chatId, msgId, sessionId, stockData, rawAnalysis: rawText } }];
  } else {
    return [{ json: { chatId, msgId, sessionId, stockData: null, rawAnalysis: rawText, error: 'JSON 파싱 실패' } }];
  }
} catch (e) {
  return [{ json: { chatId, msgId, sessionId, stockData: null, error: `분석 오류: ${e.message}` } }];
}

// ─── Generate Trading Recommendations ─────────────────────────────────────
const OPENCODE_URL = 'http://opencode-proxy:3284';
const { chatId, msgId, sessionId, stockData, rawAnalysis, error } = $json;

if (!stockData || error) {
  return [{ json: { chatId, msgId, sessionId, report: null, stockData: null, error: error || '주식 데이터를 추출할 수 없습니다.' } }];
}

const today = new Date().toISOString().split('T')[0];
const stockList = stockData.stocks.map(s => 
  `- ${s.name} (${s.ticker || 'N/A'}): ${s.shares}주, 평가액 ${s.totalValue?.toLocaleString()}원, 수익 ${s.profitLoss?.toLocaleString()}원 (${s.profitLossPercent}%), 시장: ${s.market}`
).join('\n');

const recommendPrompt = `당신은 전문 투자 애널리스트입니다. 오늘 날짜는 ${today}입니다.

아래는 사용자의 주식 포트폴리오입니다:
${stockList}

총 포트폴리오 가치: ${stockData.totalPortfolioValue?.toLocaleString()}원
총 수익/손실: ${stockData.totalProfitLoss?.toLocaleString()}원 (${stockData.overallProfitPercent}%)

각 종목에 대해 오늘 장 마감 전까지 어떤 행동을 취해야 하는지 분석해주세요.

각 종목마다 다음을 포함해주세요:
1. 추천 행동: 매수(BUY) / 매도(SELL) / 홀드(HOLD) / 부분매도(PARTIAL_SELL)
2. 추천 이유 (2-3문장)
3. 리스크 수준: 상(HIGH) / 중(MEDIUM) / 하(LOW)
4. 목표가 또는 손절가 (가능한 경우)

마지막에 전체 포트폴리오에 대한 총평도 작성해주세요.

반드시 아래 JSON 형식으로만 답변하세요:
{
  "recommendations": [
    {
      "name": "종목명",
      "action": "HOLD",
      "reason": "이유...",
      "risk": "MEDIUM",
      "targetPrice": "목표가 또는 N/A"
    }
  ],
  "portfolioSummary": "전체 포트폴리오 총평...",
  "marketOutlook": "오늘 시장 전망..."
}`;

try {
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: `${OPENCODE_URL}/run`,
    body: { prompt: recommendPrompt, chatId: String(chatId) },
    json: true,
    timeout: 300000
  });

  let rawText = result.text || '';
  const jsonMatch = rawText.match(/\{[\s\S]*\"recommendations\"[\s\S]*\}/);
  if (jsonMatch) {
    const recommendations = JSON.parse(jsonMatch[0]);
    return [{ json: { chatId, msgId, sessionId, stockData, recommendations } }];
  } else {
    return [{ json: { chatId, msgId, sessionId, stockData, recommendations: null, rawRecommendation: rawText } }];
  }
} catch (e) {
  return [{ json: { chatId, msgId, sessionId, stockData, recommendations: null, error: `추천 생성 오류: ${e.message}` } }];
}

// ─── Format Stock Report for Telegram ─────────────────────────────────────
const { chatId, msgId, sessionId, stockData, recommendations, rawRecommendation, error } = $json;

function escapeHTML(str) {
  return String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

if (error && !stockData) {
  const formattedText = `❌ <b>주식 분석 오류</b>\n\n${escapeHTML(error)}\n\n💡 /stock 명령어와 함께 주식 포트폴리오 스크린샷을 보내주세요.`;
  return [{ json: { chatId, msgId, formattedText, sessionId } }];
}

let report = '📊 <b>주식 포트폴리오 분석 리포트</b>\n';
report += `📅 ${new Date().toLocaleDateString('ko-KR', { year: 'numeric', month: 'long', day: 'numeric' })}\n\n`;

// ─── Portfolio Summary ───
if (stockData) {
  report += '━━━━━━━━━━━━━━━━━━━━\n';
  report += '💰 <b>포트폴리오 요약</b>\n';
  report += `총 평가액: <code>${stockData.totalPortfolioValue?.toLocaleString()}원</code>\n`;
  const plEmoji = stockData.totalProfitLoss >= 0 ? '📈' : '📉';
  report += `총 수익: ${plEmoji} <code>${stockData.totalProfitLoss?.toLocaleString()}원 (${stockData.overallProfitPercent}%)</code>\n`;
  report += `보유 종목: <code>${stockData.stocks?.length || 0}개</code>\n\n`;

  // ─── Individual Stocks ───
  report += '━━━━━━━━━━━━━━━━━━━━\n';
  report += '📋 <b>종목별 현황</b>\n\n';

  const domesticStocks = (stockData.stocks || []).filter(s => s.market === 'domestic');
  const overseasStocks = (stockData.stocks || []).filter(s => s.market === 'overseas');

  if (domesticStocks.length > 0) {
    report += '🇰🇷 <b>국내</b>\n';
    for (const s of domesticStocks) {
      const emoji = (s.profitLoss || 0) >= 0 ? '🟢' : '🔴';
      report += `${emoji} <b>${escapeHTML(s.name)}</b>\n`;
      report += `   ${s.shares}주 | ${s.totalValue?.toLocaleString()}원 | ${(s.profitLoss || 0) >= 0 ? '+' : ''}${s.profitLoss?.toLocaleString()}원 (${s.profitLossPercent}%)\n`;
    }
    report += '\n';
  }

  if (overseasStocks.length > 0) {
    report += '🌍 <b>해외</b>\n';
    for (const s of overseasStocks) {
      const emoji = (s.profitLoss || 0) >= 0 ? '🟢' : '🔴';
      report += `${emoji} <b>${escapeHTML(s.name)}</b>\n`;
      report += `   ${s.shares}주 | ${s.totalValue?.toLocaleString()}원 | ${(s.profitLoss || 0) >= 0 ? '+' : ''}${s.profitLoss?.toLocaleString()}원 (${s.profitLossPercent}%)\n`;
    }
    report += '\n';
  }
}

// ─── Recommendations ───
if (recommendations && recommendations.recommendations) {
  report += '━━━━━━━━━━━━━━━━━━━━\n';
  report += '🎯 <b>오늘의 투자 전략</b>\n\n';

  for (const rec of recommendations.recommendations) {
    let actionEmoji = '⏸️';
    let actionText = rec.action;
    if (rec.action === 'BUY') { actionEmoji = '🟢'; actionText = '매수'; }
    else if (rec.action === 'SELL') { actionEmoji = '🔴'; actionText = '매도'; }
    else if (rec.action === 'HOLD') { actionEmoji = '⏸️'; actionText = '홀드'; }
    else if (rec.action === 'PARTIAL_SELL') { actionEmoji = '🟡'; actionText = '부분매도'; }

    let riskEmoji = '🟢';
    if (rec.risk === 'HIGH') riskEmoji = '🔴';
    else if (rec.risk === 'MEDIUM') riskEmoji = '🟡';

    report += `${actionEmoji} <b>${escapeHTML(rec.name)}</b> → <b>${actionText}</b>\n`;
    report += `   📝 ${escapeHTML(rec.reason)}\n`;
    report += `   ${riskEmoji} 리스크: ${rec.risk} | 🎯 ${escapeHTML(rec.targetPrice || 'N/A')}\n\n`;
  }

  if (recommendations.marketOutlook) {
    report += '━━━━━━━━━━━━━━━━━━━━\n';
    report += `🌐 <b>시장 전망</b>\n${escapeHTML(recommendations.marketOutlook)}\n\n`;
  }

  if (recommendations.portfolioSummary) {
    report += '━━━━━━━━━━━━━━━━━━━━\n';
    report += `📌 <b>총평</b>\n${escapeHTML(recommendations.portfolioSummary)}\n\n`;
  }
} else if (rawRecommendation) {
  report += '━━━━━━━━━━━━━━━━━━━━\n';
  report += `🎯 <b>투자 분석</b>\n${escapeHTML(rawRecommendation).slice(0, 2000)}\n\n`;
}

report += `\n🏷️ <b>Session:</b> <code>${sessionId || 'none'}</code>`;
report += `\n⚠️ <i>본 리포트는 AI 분석 결과이며 투자 조언이 아닙니다. 투자 결정은 본인 판단에 따라 주세요.</i>`;

// Telegram 4096 char limit
if (report.length > 4090) {
  report = report.slice(0, 4080) + '\n...(생략)';
}

return [{ json: { chatId, msgId, formattedText: report, sessionId } }];

// ─── Run OpenCode ────────────────────────────────────────────────────────────
const OPENCODE_URL = 'http://opencode-proxy:3284';
const TIMEOUT = 300000;

const routeData = $('Route by Command').first().json;
const message = routeData.message || '';
const chatId  = routeData.chatId;
const msgId   = routeData.msgId;
const sessionIdDisplay = $json.sessionId || routeData.sessionId || 'none';

if (routeData.responseText) {
  const formattedText = `🤖 <b>Model:</b> <code>System</code>\n\n${routeData.responseText}\n\n🏷️ <b>Session:</b> <code>${sessionIdDisplay}</code>`;
  return [{ json: { chatId, msgId, formattedText, model: 'System', text: routeData.responseText, sessionId: sessionIdDisplay } }];
}

if (!message) {
  return [{ json: { chatId, msgId, formattedText: '(메시지가 비어있습니다)', sessionId: sessionIdDisplay } }];
}

function escapeHTML(str) {
  return str.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

try {
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: `${OPENCODE_URL}/run`,
    body: { prompt: message, chatId: String(chatId) },
    json: true,
    timeout: TIMEOUT
  });

  const model = result.model || 'OpenCode';
  let text = result.text || '(no output)';

  if (text.length > 3900) {
    text = text.slice(0, 3900) + "\n\n... (Truncated)";
  }

  const returnedSession = result.sessionId ? result.sessionId.replace(/^ses_/, '') : sessionIdDisplay;
  const formattedText = `🤖 <b>Model:</b> <code>${escapeHTML(model)}</code>\n\n${escapeHTML(text)}\n\n🏷️ <b>Session:</b> <code>${escapeHTML(returnedSession)}</code>`;

  return [{ json: { chatId, msgId, formattedText, model, text, sessionId: returnedSession } }];
} catch (e) {
  const errMsg = (e.message || '').slice(0, 500);
  const formattedText = `❌ <b>오류:</b>\n<pre>${escapeHTML(errMsg)}</pre>\n\n🏷️ <b>Session:</b> <code>${escapeHTML(sessionIdDisplay)}</code>`;
  return [{ json: { chatId, msgId, formattedText, error: true, sessionId: sessionIdDisplay } }];
}
